// ============================================================================
// clamp
// ============================================================================
describe('clamp', () => {
  it('returns value when within range', () => {
    expect(clamp(5, 0, 10)).toBe(5);
  });

  it('clamps to min when below', () => {
    expect(clamp(-5, 0, 10)).toBe(0);
  });

  it('clamps to max when above', () => {
    expect(clamp(15, 0, 10)).toBe(10);
  });

  it('handles equal min and max', () => {
    expect(clamp(5, 3, 3)).toBe(3);
  });

  it('handles exact boundary values', () => {
    expect(clamp(0, 0, 10)).toBe(0);
    expect(clamp(10, 0, 10)).toBe(10);
  });
});

// ============================================================================
// clampDuration
// ============================================================================
describe('clampDuration', () => {
  it('returns 0 for zero or negative durations', () => {
    expect(clampDuration(0)).toBe(0);
    expect(clampDuration(-1)).toBe(0);
  });

  it('clamps to MIN_DURATION when too small but positive', () => {
    expect(clampDuration(0.1)).toBe(MIN_DURATION);
  });

  it('clamps to MAX_DURATION when too large', () => {
    expect(clampDuration(5)).toBe(MAX_DURATION);
  });

  it('returns value when within range', () => {
    expect(clampDuration(1.0)).toBe(1.0);
  });
});

// ============================================================================
// easing functions
// ============================================================================
describe('easeInOutCubic', () => {
  it('returns 0 at t=0', () => {
    expect(easeInOutCubic(0)).toBe(0);
  });

  it('returns 1 at t=1', () => {
    expect(easeInOutCubic(1)).toBe(1);
  });

  it('returns 0.5 at t=0.5', () => {
    expect(easeInOutCubic(0.5)).toBe(0.5);
  });

  it('clamps values below 0', () => {
    expect(easeInOutCubic(-1)).toBe(0);
  });

  it('clamps values above 1', () => {
    expect(easeInOutCubic(2)).toBe(1);
  });

  it('is less than 0.5 for t < 0.5', () => {
    expect(easeInOutCubic(0.3)).toBeLessThan(0.5);
  });

  it('is greater than 0.5 for t > 0.5', () => {
    expect(easeInOutCubic(0.7)).toBeGreaterThan(0.5);
  });
});

describe('easeOutCubic', () => {
  it('returns 0 at t=0', () => {
    expect(easeOutCubic(0)).toBe(0);
  });

  it('returns 1 at t=1', () => {
    expect(easeOutCubic(1)).toBe(1);
  });

  it('decelerates (value > linear at midpoint)', () => {
    expect(easeOutCubic(0.5)).toBeGreaterThan(0.5);
  });
});

describe('easeInCubic', () => {
  it('returns 0 at t=0', () => {
    expect(easeInCubic(0)).toBe(0);
  });

  it('returns 1 at t=1', () => {
    expect(easeInCubic(1)).toBe(1);
  });

  it('accelerates (value < linear at midpoint)', () => {
    expect(easeInCubic(0.5)).toBeLessThan(0.5);
  });
});

