// ============================================================================
// computeTransitionProgress
// ============================================================================
describe('computeTransitionProgress', () => {
  it('returns 1 when transitionFrames is 0', () => {
    expect(computeTransitionProgress(5, 30, 0, false)).toBe(1);
  });

  it('returns 1 when totalFrames is 0', () => {
    expect(computeTransitionProgress(0, 0, 10, false)).toBe(1);
  });

  it('entry: returns 0 at frame 0', () => {
    expect(computeTransitionProgress(0, 30, 10, false)).toBe(0);
  });

  it('entry: returns 1 after transition frames end', () => {
    expect(computeTransitionProgress(15, 30, 10, false)).toBe(1);
  });

  it('entry: returns 0.5 at midpoint', () => {
    expect(computeTransitionProgress(5, 30, 10, false)).toBe(0.5);
  });

  it('exit: returns 1 before exit starts', () => {
    expect(computeTransitionProgress(5, 30, 10, true)).toBe(1);
  });

  it('exit: returns 0 at last frame', () => {
    expect(computeTransitionProgress(30, 30, 10, true)).toBe(0);
  });

  it('exit: returns 0.5 at midpoint of exit', () => {
    expect(computeTransitionProgress(25, 30, 10, true)).toBe(0.5);
  });
});

