// ============================================================================
// computeTransitionStyle
// ============================================================================
describe('computeTransitionStyle', () => {
  const w = 200;
  const h = 100;

  it('none: always fully visible', () => {
    const s = computeTransitionStyle('none', 0, w, h);
    expect(s.opacity).toBe(1);
    expect(s.transform).toBe('none');
  });

  it('fade: opacity 0 at progress 0', () => {
    const s = computeTransitionStyle('fade', 0, w, h);
    expect(s.opacity).toBe(0);
  });

  it('fade: opacity 1 at progress 1', () => {
    const s = computeTransitionStyle('fade', 1, w, h);
    expect(s.opacity).toBe(1);
  });

  it('slideLeft: translateX from width to 0', () => {
    const s0 = computeTransitionStyle('slideLeft', 0, w, h);
    expect(s0.transform).toContain('translateX');
    expect(s0.opacity).toBe(1);

    const s1 = computeTransitionStyle('slideLeft', 1, w, h);
    expect(s1.transform).toContain('translateX(0px)');
  });

  it('slideRight: translateX from negative to 0', () => {
    const s0 = computeTransitionStyle('slideRight', 0, w, h);
    expect(s0.transform).toContain('translateX');

    const s1 = computeTransitionStyle('slideRight', 1, w, h);
    expect(s1.transform).toContain('translateX(0px)');
  });

  it('zoom: scale from 0.7 to 1', () => {
    const s0 = computeTransitionStyle('zoom', 0, w, h);
    expect(s0.transform).toContain('scale(0.7)');

    const s1 = computeTransitionStyle('zoom', 1, w, h);
    expect(s1.transform).toContain('scale(1)');
  });

  it('dissolve: opacity from 0 with slight scale', () => {
    const s0 = computeTransitionStyle('dissolve', 0, w, h);
    expect(s0.opacity).toBe(0);

    const s1 = computeTransitionStyle('dissolve', 1, w, h);
    expect(s1.opacity).toBe(1);
  });
});

// ============================================================================
// computeWipeClipPath
// ============================================================================
describe('computeWipeClipPath', () => {
  it('returns undefined for non-wipe types', () => {
    expect(computeWipeClipPath('fade', 0.5)).toBeUndefined();
    expect(computeWipeClipPath('none', 0.5)).toBeUndefined();
  });

  it('wipe: returns inset at progress 0', () => {
    const clip = computeWipeClipPath('wipe', 0);
    expect(clip).toContain('inset');
    expect(clip).toContain('100%');
  });

  it('wipe: returns inset 0 at progress 1', () => {
    const clip = computeWipeClipPath('wipe', 1);
    expect(clip).toContain('0%');
  });

  it('wipeLeft: returns inset at progress 0', () => {
    const clip = computeWipeClipPath('wipeLeft', 0);
    expect(clip).toContain('inset');
    expect(clip).toContain('100%');
  });
});

// ============================================================================
// generateFFmpegTransitionFilter
// ============================================================================
describe('generateFFmpegTransitionFilter', () => {
  it('returns empty for none type', () => {
    expect(generateFFmpegTransitionFilter('none', 0.5, 5)).toBe('');
  });

  it('returns empty for zero duration', () => {
    expect(generateFFmpegTransitionFilter('fade', 0, 5)).toBe('');
  });

  it('returns xfade filter for fade', () => {
    const f = generateFFmpegTransitionFilter('fade', 0.5, 5);
    expect(f).toContain('xfade=transition=fade');
    expect(f).toContain('duration=0.5');
    expect(f).toContain('offset=5');
  });

  it('maps slideLeft to slideleft', () => {
    const f = generateFFmpegTransitionFilter('slideLeft', 0.5, 3);
    expect(f).toContain('slideleft');
  });

  it('maps wipe to wiperight', () => {
    const f = generateFFmpegTransitionFilter('wipe', 0.6, 10);
    expect(f).toContain('wiperight');
  });

  it('clamps duration', () => {
    const f = generateFFmpegTransitionFilter('fade', 5.0, 10);
    expect(f).toContain(`duration=${MAX_DURATION}`);
  });
});

// ============================================================================
// computeTotalDurationWithTransitions
// ============================================================================
describe('computeTotalDurationWithTransitions', () => {
  it('returns 0 for empty array', () => {
    expect(computeTotalDurationWithTransitions([], [])).toBe(0);
  });

  it('returns single scene duration', () => {
    expect(computeTotalDurationWithTransitions([5], [])).toBe(5);
  });

  it('subtracts overlap for transitions', () => {
    const durations = [5, 5];
    const transitions: TransitionConfig[] = [{ type: 'fade', duration: 0.5 }];
    expect(computeTotalDurationWithTransitions(durations, transitions)).toBe(9.5);
  });

  it('no overlap for none transitions', () => {
    const durations = [5, 5];
    const transitions: TransitionConfig[] = [{ type: 'none', duration: 0 }];
    expect(computeTotalDurationWithTransitions(durations, transitions)).toBe(10);
  });

  it('handles multiple scenes', () => {
    const durations = [5, 5, 5];
    const transitions: TransitionConfig[] = [
      { type: 'fade', duration: 0.5 },
      { type: 'zoom', duration: 1.0 },
    ];
    // 5 + (5-0.5) + (5-1.0) = 5 + 4.5 + 4 = 13.5
    expect(computeTotalDurationWithTransitions(durations, transitions)).toBe(13.5);
  });
});

// ============================================================================
// serializeTransition / deserializeTransition
// ============================================================================
describe('serializeTransition', () => {
  it('returns "none" for none type', () => {
    expect(serializeTransition({ type: 'none', duration: 0 })).toBe('none');
  });

  it('returns type:duration format', () => {
    expect(serializeTransition({ type: 'fade', duration: 0.5 })).toBe('fade:0.5');
  });
});

describe('deserializeTransition', () => {
  it('returns none for empty string', () => {
    const c = deserializeTransition('');
    expect(c.type).toBe('none');
    expect(c.duration).toBe(0);
  });

  it('returns none for "none"', () => {
    const c = deserializeTransition('none');
    expect(c.type).toBe('none');
  });

  it('parses type:duration format', () => {
    const c = deserializeTransition('fade:0.8');
    expect(c.type).toBe('fade');
    expect(c.duration).toBe(0.8);
  });

  it('uses default duration when no duration provided', () => {
    const c = deserializeTransition('zoom');
    expect(c.type).toBe('none');  // 'zoom' alone without ':' will split to ['zoom', undefined]
  });

  it('falls back to none for invalid type', () => {
    const c = deserializeTransition('invalid:0.5');
    expect(c.type).toBe('none');
  });

  it('roundtrips correctly', () => {
    const original: TransitionConfig = { type: 'slideLeft', duration: 1.0 };
    const serialized = serializeTransition(original);
    const deserialized = deserializeTransition(serialized);
    expect(deserialized.type).toBe(original.type);
    expect(deserialized.duration).toBe(original.duration);
  });
});

